#include <bits/stdc++.h>
using namespace std;
int di[4][2]={{-1,0},{1,0},{0,-1},{0,1}};
int n,a[31][31];
bool check(int sx,int sy){
    bool to[31][31];
    queue<int> x,y;
    memset(to,0,sizeof(to));
    x.push(sx),y.push(sy),to[sx][sy]=1;
    while(x.size()){
        int fx=x.front(),fy=y.front();
        x.pop(),y.pop();
        for(int i=0;i<4;i++){
            int xx=fx+di[i][0],yy=fy+di[i][1];
            if(xx>0 && yy>0 && xx<=n && yy<=n && !to[xx][yy] && !a[xx][yy])
                if(xx==1 || yy==1 || xx==n || yy==n)
                    return false;
                else
                    x.push(xx),y.push(yy),to[xx][yy]=1;
        }
    }
    return true;
}
void paint(int sx,int sy){
    queue<int> x,y;
    x.push(sx),y.push(sy),a[sx][sy]=2;
    while(x.size()){
        int fx=x.front(),fy=y.front();
        x.pop(),y.pop();
        for(int i=0;i<4;i++){
            int xx=fx+di[i][0],yy=fy+di[i][1];
            if(xx>0 && yy>0 && xx<=n && yy<=n && !a[xx][yy])
                x.push(xx),y.push(yy),a[xx][yy]=2;
        }
    }
}
int main(){
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
        for(int j=1;j<=n;j++)
            scanf("%d",&a[i][j]);
    for(int i=2;i<n;i++)
        for(int j=2;j<n;j++)
            if(!a[i][j] && check(i,j))
                paint(i,j);
    for(int i=1;i<=n;i++){
        for(int j=1;j<=n;j++)
            printf("%d ",a[i][j]);
        printf("\n");
    }
    return 0;
}
